import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);

  useEffect(() => {
    fetchDespesas();
  }, []);

  async function fetchDespesas() {
    const { data, error } = await supabase
      .from('compras')
      .select('*')
      .order('data_compra', { ascending: false });
    
    if (error) console.log('Erro:', error);
    else setDespesas(data);
  }

  return (
    <div>
      <h2>Histórico de Despesas</h2>
      <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
        <thead>
          <tr style={{ textAlign: 'left', borderBottom: '2px solid #eee' }}>
            <th>Data</th>
            <th>Descrição / Loja</th>
            <th>Parcelas</th>
            <th>Valor Total</th>
          </tr>
        </thead>
        <tbody>
          {despesas.map((item) => (
            <tr key={item.id} style={{ borderBottom: '1px solid #eee' }}>
              <td>{new Date(item.data_compra).toLocaleDateString()}</td>
              <td>
                <strong>{item.descricao}</strong> <br />
                <small style={{ color: '#666' }}>Loja: {item.loja || 'Não informada'}</small>
              </td>
              <td>{item.parcelado ? `${item.num_parcelas}x` : 'À vista'}</td>
              <td>R$ {item.valor_total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Listagem;
